#counting the frequency of specific sentiments, looking at most common words in anger sentiment.
get_sentiments("nrc") |&gt; 
  filter(sentiment == "anger") |&gt;
  inner_join(tidy_tweet) |&gt;
  count(word, sort = TRUE) |&gt;
  slice_max(n, n = 10)


